import { getBaseMark4BarMarker } from '../bar/bar-marker-helpers';
import { ParserRegistry } from '../core/parser-registry';

export function _medianMark(data, phase, condition) {
    const KEY = 'median',
        KEY_MERGED = 'medianOptionsMerged';

    let _this = this,
        highlightPhase = phase === 'highlight',
        options = highlightPhase ? this.builderC[KEY_MERGED].hoveroptions : this.builderC[KEY_MERGED];

    let _medianG = {
        mark: 'g',
        selector: `.medianSeries${this.builderC.datasetIndex}`,
        data: !condition || data.disabled ? [] : [data.data],
        children: []
    };
    if(condition){
        let args_data = highlightPhase ? data.data : null;
        let _medianMark = getBaseMark4BarMarker.call(this, KEY, args_data, options);
        _medianG.children.push(_medianMark);
    }
    return _medianG;
}

ParserRegistry.marks('boxplot.median', _medianMark);
